```typescript
import { Effect, Request, RequestResolver } from "effect";

interface User { readonly id: string; readonly name: string }

// Tagged request: success = User, error = never (batch lookup cannot fail here).
class GetUser extends Request.TaggedClass("GetUser")<User, never, { readonly id: string }> {}

// Batched resolver — receives every concurrent GetUser in one array.
const UserResolver = RequestResolver.makeBatched((requests: ReadonlyArray<GetUser>) =>
  Effect.gen(function* () {
    // Simulated single round-trip DB hit for N ids.
    const rows: ReadonlyArray<User> = requests.map((r) => ({ id: r.id, name: `user-${r.id}` }));
    yield* Effect.forEach(requests, (r, i) => Request.succeed(r, rows[i]!), { discard: true });
  }),
);

const getUser = (id: string): Effect.Effect<User> =>
  Effect.request(new GetUser({ id }), UserResolver);

// Three lookups in one fiber — resolver sees them as a single batch.
export const program: Effect.Effect<ReadonlyArray<User>> = Effect.all(
  [getUser("1"), getUser("2"), getUser("3")],
  { concurrency: "unbounded", batching: true },
);
```

A raw `Effect.all` runs N independent effects — each one does its own I/O round-trip. `Effect.Request` separates the *description* of a lookup from the *execution*: you define a typed `Request`, then hand it to a `RequestResolver.makeBatched` that receives every concurrent request as one array. The runtime deduplicates identical requests and collapses N calls into a single batch round-trip, while each caller still sees its own `Effect<Value>`.

