import { Effect, Request, RequestResolver, Data } from "effect";

interface Comment { readonly id: string; readonly postId: string; readonly body: string }

class NotFound extends Data.TaggedError("NotFound")<{ readonly postId: string }> {}

class GetComments extends Request.TaggedClass("GetComments")<
  ReadonlyArray<Comment>,
  NotFound,
  { readonly postId: string }
> {}

// Fake store: only posts "1" and "2" exist.
const store: ReadonlyMap<string, ReadonlyArray<Comment>> = new Map([
  ["1", [{ id: "c1", postId: "1", body: "hi" }]],
  ["2", [{ id: "c2", postId: "2", body: "yo" }]],
]);

const CommentResolver = RequestResolver.makeBatched((reqs: ReadonlyArray<GetComments>) =>
  Effect.forEach(
    reqs,
    (r) => {
      const rows = store.get(r.postId);
      return rows === undefined
        ? Request.fail(r, new NotFound({ postId: r.postId }))
        : Request.succeed(r, rows);
    },
    { discard: true },
  ),
);

export const getComments = (postId: string): Effect.Effect<ReadonlyArray<Comment>, NotFound> =>
  Effect.request(new GetComments({ postId }), CommentResolver);
