import { Cache, Data, Duration, Effect } from "effect";

interface Profile { readonly id: string; readonly name: string }
class FetchError extends Data.TaggedError("FetchError")<{ readonly reason: string }> {}

declare const slowFetch: (id: string) => Effect.Effect<Profile, FetchError>;

export const program: Effect.Effect<Profile, FetchError> = Effect.gen(function* () {
  const cache = yield* Cache.make({
    capacity: 512,
    timeToLive: Duration.minutes(5),
    lookup: (id: string): Effect.Effect<Profile, FetchError> => slowFetch(id),
  });
  // First call computes; subsequent calls within 5 minutes return the cached value.
  return yield* cache.get("user-42");
});
```

`Cache.make` takes a `lookup: (key) => Effect<Value, Error, R>` and a `timeToLive`. Calling `cache.get(key)` returns the cached value when one exists and has not exceeded the TTL; otherwise it re-invokes `lookup(key)` and stores the fresh result. The TTL is checked on access, not on a background timer, so stale entries simply trigger a refetch on the next read. Failed lookups are cached too (same TTL), so repeated failures don't hammer the upstream — use `cache.invalidate` to force a retry.

