import { Effect, Queue } from "effect";

export const program: Effect.Effect<number> = Effect.gen(function* () {
  const queue = yield* Queue.bounded<number>(16);

  // Producer — runs in the same fiber via forkDaemon so we can await the consumer.
  yield* Effect.forkDaemon(
    Effect.forEach([1, 2, 3, 4, 5], (n) => Queue.offer(queue, n), { discard: true }),
  );

  // Consumer — take 5 and sum.
  let total = 0;
  for (let i = 0; i < 5; i += 1) {
    total += yield* Queue.take(queue);
  }
  return total;
});
