import { Chunk, Effect, Queue } from "effect";

export const drainDemo: Effect.Effect<ReadonlyArray<string>> = Effect.gen(function* () {
  const q = yield* Queue.unbounded<string>();
  yield* Queue.offer(q, "a");
  yield* Queue.offer(q, "b");
  yield* Queue.offer(q, "c");

  // takeAll returns a Chunk of everything currently queued (can be empty).
  const chunk = yield* Queue.takeAll(q);
  return Chunk.toReadonlyArray(chunk);
});
