import { Effect, Fiber, PubSub, Queue } from "effect";

export const program: Effect.Effect<readonly [string[], string[]]> = Effect.scoped(
  Effect.gen(function* () {
    const hub = yield* PubSub.bounded<string>(8);

    // Each subscribe returns a Dequeue scoped to the caller's scope.
    const sub1 = yield* PubSub.subscribe(hub);
    const sub2 = yield* PubSub.subscribe(hub);

    const reader = (q: Queue.Dequeue<string>): Effect.Effect<string[]> =>
      Effect.gen(function* () {
        const out: string[] = [];
        for (let i = 0; i < 3; i += 1) out.push(yield* Queue.take(q));
        return out;
      });

    const f1 = yield* Effect.fork(reader(sub1));
    const f2 = yield* Effect.fork(reader(sub2));

    yield* Effect.forEach(["a", "b", "c"], (s) => PubSub.publish(hub, s), { discard: true });

    const a = yield* Fiber.join(f1);
    const b = yield* Fiber.join(f2);
    return [a, b] as const;
  }),
);
