// error branch instead of wrapping a try/catch.
export const divide = (a: number, b: number): IOE.IOEither<Error, number> => () =>
  b === 0
    ? { _tag: "Left", left: new Error("div-by-zero") }
    : { _tag: "Right", right: a / b };

