import { pipe } from "fp-ts/function";
import * as IOE from "fp-ts/IOEither";

// Don't throw inside the thunk — return a Left so the error flows through the
// monad instead of escaping the pipeline.
export const readN = (raw: string): IOE.IOEither<Error, number> => () => {
  const n = Number(raw);
  return Number.isNaN(n)
    ? { _tag: "Left", left: new Error("NaN") }
    : { _tag: "Right", right: n };
};

// Consumer pipeline — IOE.map only fires on Right, so the throw is now typed.
export const doubled = (raw: string): IOE.IOEither<Error, number> =>
  pipe(readN(raw), IOE.map((n) => n * 2));
