import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RA from "fp-ts/ReadonlyArray";

interface Row { readonly id: string; readonly n: number }

const parseRow = (raw: string): E.Either<string, Row> => {
  const [id, nRaw] = raw.split(":");
  if (id === undefined || nRaw === undefined) return E.left(`malformed: ${raw}`);
  const n = Number(nRaw);
  return Number.isNaN(n) ? E.left(`not a number: ${nRaw}`) : E.right({ id, n });
};

export const parseAll = (
  inputs: ReadonlyArray<string>,
): { readonly left: ReadonlyArray<string>; readonly right: ReadonlyArray<Row> } =>
  pipe(inputs, RA.partitionMap(parseRow));
```

- `RA.map(f)` — one-in, one-out; `f: A => B`. Shape preserved.
- `RA.chain(f)` — one-in, many-out; `f: A => ReadonlyArray<B>`. Flattens the result (monadic bind).
- `RA.filterMap(f)` — one-in, zero-or-one-out; `f: A => Option<B>`. Replaces `filter` + `map` when the predicate and the transform share work.

