import { Effect } from "effect";

interface Response { readonly url: string; readonly status: number }

declare const fetchOne: (url: string) => Effect.Effect<Response>;

export const fetchAllBounded = (
  urls: ReadonlyArray<string>,
): Effect.Effect<ReadonlyArray<Response>> =>
  Effect.gen(function* () {
    const sem = yield* Effect.makeSemaphore(3);
    // withPermits(1) wraps each effect so at most 3 run at once.
    return yield* Effect.all(
      urls.map((u) => sem.withPermits(1)(fetchOne(u))),
      { concurrency: "unbounded" },
    );
  });
